from llama_stack_client import LlamaSafetyClient
import vex

safety_client = LlamaSafetyClient()

@vex.verify(metric='safety_rejection_rate')
def monitor_safety_cost(query: str) -> dict:
    safety_check = safety_client.check(query)
    rejection_rate = safety_check.get('rejected', False)
    tokens_wasted = safety_check.get('tokens_used', 0)

    if rejection_rate and 'benign' in query.lower():
        raise vex.CostIssue(f"False positive: {tokens_wasted} tokens wasted")

    return {'safe': True, 'tokens': tokens_wasted}

from llama_stack_client import LlamaToolsClient
import json

tools_client = LlamaToolsClient()

@vex.verify(metric='tool_response_bloat')
def validate_tool_schema(tool_call: dict):
    response = tools_client.execute(tool_call)

    if len(response['content']) > 2000:
        raise vex.CostIssue(f"Tool response bloated: {len(response['content'])} chars")

    try:
        json.loads(response['content'])
    except json.JSONDecodeError:
        raise vex.CostIssue("Tool response not JSON schema compliant")

    return {'valid': True, 'tokens': len(response['content']) // 4}

