from llama_stack_client import LlamaAgentClient

agent = LlamaAgentClient(max_turns=10)

@vex.guardrail
class CostOptimizedAgent:
    def __init__(self):
        self.progress_states = set()

    def should_terminate(self, state: dict):
        current_state = state.get('task_status', 'unknown')

        if len(self.progress_states) > 3:
            # No progress in 3+ turns
            return True

        self.progress_states.add(current_state)
        return agent.turn_count >= 4

    def run_with_early_exit(self, query: str):
        while not self.should_terminate(agent.state):
            agent.step(query)
        return agent.final_response
